async function seedAll() {
  const { getFirestore, collection, addDoc, getDocs, query } = await import('https://www.gstatic.com/firebasejs/10.12.0/firebase-firestore.js');
  const db = getFirestore();
  
  // Check if already seeded
  const existing = await getDocs(query(collection(db, 'games')));
  if (existing.size > 50) {
    console.log('Already seeded! Games found:', existing.size);
    return;
  }
  
  console.log('Seeding completed games...');
  let i = 1;
  for (const g of COMPLETED) {
    await addDoc(collection(db, 'games'), {
      number: i++,
      title: g.title,
      genre: g.genre,
      hltb: g.hltb,
      metacritic: g.metacritic,
      platform: g.platform,
      rating: g.rating,
      review: g.review,
      comments: g.comments,
      coverUrl: null,
      developer: '',
      year: null,
      description: '',
      status: 'Completed'
    });
    console.log('Added completed:', g.title);
  }
  
  console.log('Seeding backlog...');
  let j = 1;
  for (const g of BACKLOG) {
    await addDoc(collection(db, 'backlog'), {
      number: j++,
      title: g.title,
      genre: g.genre,
      hltb: g.hltb,
      metacritic: g.metacritic,
      platform: g.platform,
      status: g.status,
      coverUrl: null,
    });
    console.log('Added backlog:', g.title);
  }
  
  console.log('SEED COMPLETE. Refresh the page.');
}

seedAll();
